fn check_pool_stake_authority_address(
    program_id: &Pubkey, pool_key: &Pubkey, authority_key: &Pubkey,
) -> Result<u8, ProgramError> {
    let (expected_authority, bump) = crate::find_pool_stake_authority_address(program_id, pool_key);
    if expected_authority != *authority_key {
        Err(SinglePoolError::InvalidPoolStakeAuthority.into())
    } else {
        Ok(bump)
    }
}
